import styled from "@emotion/styled";
import { Link } from "gatsby";
import React from "react";
import { GatsbyImage } from "gatsby-plugin-image";

const PostItemWrapper = styled(Link)`
  display: flex;
  flex-direction: column;
  border-radius: 10px;
  box-shadow: 0 0 10px rgba(255, 255, 255, 0.1);
  transition: 0.3s box-shadow;
  position: relative;
  cursor: pointer;
  color: #fff;

  &:hover {
    box-shadow: 0 0 20px rgba(255, 255, 255, 0.3);
    color: #fff;
  }
`;

const PostItemContent = styled.div`
  flex: 1;
  display: flex;
  flex-direction: column;
  padding: 15px;
`;

const ThumbnailImage = styled(GatsbyImage)`
  width: 100%;
  height: 200px;
  border-radius: 10px 10px 0 0;

  @media (max-width: 768px) {
    display: none;
  }
`;

const Title = styled.div`
  display: -webkit-box;
  overflow: hidden;
  margin-bottom: 3px;
  text-overflow: ellipsis;
  white-space: normal;
  overflow-wrap: break-word;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  font-size: 20px;
  font-weight: 700;
`;

const Date = styled.div`
  font-size: 14px;
  font-weight: 400;
  opacity: 0.7;
`;

const CategoryAndTag = styled.div`
  display: flex;
  align-items: center;
`;

const Tag = styled.div`
  display: flex;
  flex-wrap: wrap;
  margin-top: 10px;
  margin: 10px -5px;
`;

const TagItem = styled.div`
  margin: 2.5px 5px;
  padding: 3px 5px;
  border-radius: 3px;
  background: #3d3d3d;
  font-size: 14px;
  font-weight: 700;
`;

const Summary = styled.div`
  display: -webkit-box;
  overflow: hidden;
  margin-top: auto;
  text-overflow: ellipsis;
  white-space: normal;
  overflow-wrap: break-word;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  font-size: 16px;
  opacity: 0.8;
`;

const PostItem = ({
  title,
  date,
  tags,
  category,
  modifiedDate,
  summary,
  thumbnail: {
    childImageSharp: { gatsbyImageData },
  },
  link,
}) => {
  return (
    <PostItemWrapper to={link}>
      <PostItemContent>
        <Title>{title}</Title>
        <Date>{modifiedDate ? modifiedDate : date}</Date>
        <CategoryAndTag>
          <Tag>
            {tags.map((item) => (
              <TagItem key={item}>{item}</TagItem>
            ))}
          </Tag>
        </CategoryAndTag>
        <Summary>{summary}</Summary>
      </PostItemContent>
    </PostItemWrapper>
  );
};

export default PostItem;
